conversations.value:
**Never disable certificate validation in production.** This is one of the most dangerous security misconfigurations because it completely negates the security of HTTPS, making your application vulnerable to man-in-the-middle (MITM) attacks.

**VULNERABLE CODE**:

```javascript
const https = require('https');
const axios = require('axios');

// DANGEROUS: Disables ALL certificate validation globally
process.env.NODE_TLS_REJECT_UNAUTHORIZED = '0';

// DANGEROUS: Disables certificate validation per-request
const httpsAgent = new https.Agent({
  rejectUnauthorized: false  // Accepts ANY certificate, including attacker's
});

async function fetchSensitiveData(apiKey) {
  const response = await axios.get('https://api.payment-provider.com/transactions', {
    httpsAgent: httpsAgent,
    headers: {
      'Authorization': `Bearer ${apiKey}`
    }
  });
  return response.data;
}

// Also vulnerable: fetch with custom agent
const fetch = require('node-fetch');
async function fetchUserData(userId) {
  const response = await fetch(`https://internal-api.company.com/users/${userId}`, {
    agent: new https.Agent({ rejectUnauthorized: false })
  });
  return response.json();
}
```

**Attack Scenario** (on untrusted network):
```bash
# Attacker uses mitmproxy or Burp Suite to intercept traffic
mitmproxy --mode transparent --ssl-insecure

# All HTTPS traffic is now visible and modifiable:
# - API keys in headers are captured
# - Response data can be modified
# - Malicious code can be injected into responses
```

**Why This Is Dangerous**:
- **Complete loss of encryption guarantee**: HTTPS becomes security theater
- **Credential theft**: API keys, tokens, passwords sent in requests are exposed
- **Data manipulation**: Attacker can modify responses (inject malware, change transaction amounts)
- **Supply chain attacks**: If used in build tools, attackers can inject malicious dependencies
- **Compliance violations**: Automatic failure of PCI-DSS, HIPAA, SOC2 audits

**SECURE VERSION**:

```javascript
const https = require('https');
const axios = require('axios');
const fs = require('fs');
const tls = require('tls');

// SECURE: Default behavior validates certificates against system CA store
async function fetchSensitiveDataSecure(apiKey) {
  // No custom agent needed - Node.js validates certs by default
  const response = await axios.get('https://api.payment-provider.com/transactions', {
    headers: {
      'Authorization': `Bearer ${apiKey}`
    },
    timeout: 10000  // Always set timeouts
  });
  return response.data;
}

// SECURE: For internal/self-signed certs, provide the CA certificate
async function fetchInternalApiSecure(endpoint, token) {
  // Load your organization's CA certificate
  const caCert = fs.readFileSync('/etc/ssl/certs/company-ca.pem');

  const httpsAgent = new https.Agent({
    ca: caCert,                    // Trust only this CA
    rejectUnauthorized: true,       // Explicitly enforce validation
    minVersion: 'TLSv1.2',         // Minimum TLS version
    ciphers: tls.DEFAULT_CIPHERS   // Use secure cipher suites
  });

  const response = await axios.get(endpoint, {
    httpsAgent: httpsAgent,
    headers: { 'Authorization': `Bearer ${token}` },
    timeout: 10000
  });
  return response.data;
}

// SECURE: Certificate pinning for high-security applications
const crypto = require('crypto');

const PINNED_FINGERPRINTS = [
  'sha256/AAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAA=',  // Primary cert
  'sha256/BBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBB='   // Backup cert
];

function createPinnedAgent(pinnedFingerprints) {
  return new https.Agent({
    rejectUnauthorized: true,
    checkServerIdentity: (hostname, cert) => {
      // Standard hostname verification
      const err = tls.checkServerIdentity(hostname, cert);
      if (err) return err;

      // Certificate pinning
      const fingerprint = `sha256/${crypto
        .createHash('sha256')
        .update(cert.raw)
        .digest('base64')}`;

      if (!pinnedFingerprints.includes(fingerprint)) {
        return new Error(`Certificate fingerprint mismatch. Expected one of: ${pinnedFingerprints.join(', ')}`);
      }
      return undefined;  // Success
    }
  });
}
```

**Key Security Controls**:
- **Default certificate validation**: Node.js validates against system CA store by default - don't override it
- **Explicit CA specification**: For internal/self-signed certs, provide the CA certificate file
- **Certificate pinning**: For high-security APIs, verify the exact certificate fingerprint
- **TLS version enforcement**: Require TLS 1.2+ to prevent downgrade attacks

Great questions! Development and certificate rotation are legitimate challenges, but they require careful handling to avoid security holes that leak into production.

**PRODUCTION PATTERN**:

```javascript
const https = require('https');
const tls = require('tls');
const fs = require('fs');
const crypto = require('crypto');
const axios = require('axios');

// Environment-aware TLS configuration
class SecureHttpClient {
  constructor(options = {}) {
    this.env = process.env.NODE_ENV || 'development';
    this.logger = options.logger || console;
    this.caCerts = this.loadCACertificates();
    this.pinnedCerts = options.pinnedFingerprints || [];
    this.certRotationCallback = options.onCertRotation || null;
  }

  loadCACertificates() {
    const certs = [];

    // Always load system CA bundle in production
    if (this.env === 'production') {
      // Node.js uses system CAs by default, but you can add extras
      const extraCaPath = process.env.EXTRA_CA_CERTS;
      if (extraCaPath && fs.existsSync(extraCaPath)) {
        certs.push(fs.readFileSync(extraCaPath));
        this.logger.info(`Loaded additional CA from ${extraCaPath}`);
      }
    }

    // For development/staging, load dev CA if configured
    if (this.env !== 'production') {
      const devCaPath = process.env.DEV_CA_CERT_PATH;
      if (devCaPath && fs.existsSync(devCaPath)) {
        certs.push(fs.readFileSync(devCaPath));
        this.logger.info(`Loaded development CA from ${devCaPath}`);
      }
    }

    return certs.length > 0 ? certs : undefined;
  }

  createSecureAgent() {
    const agentOptions = {
      // NEVER disable certificate validation
      rejectUnauthorized: true,

      // Enforce modern TLS
      minVersion: 'TLSv1.2',
      maxVersion: 'TLSv1.3',

      // Secure cipher configuration
      ciphers: [
        'TLS_AES_256_GCM_SHA384',
        'TLS_CHACHA20_POLY1305_SHA256',
        'TLS_AES_128_GCM_SHA256',
        'ECDHE-RSA-AES256-GCM-SHA384',
        'ECDHE-RSA-AES128-GCM-SHA256'
      ].join(':'),

      // Connection pooling for performance
      keepAlive: true,
      maxSockets: 50,
      timeout: 30000
    };

    // Add custom CA certificates if configured
    if (this.caCerts) {
      agentOptions.ca = this.caCerts;
    }

    // Add certificate pinning for high-security mode
    if (this.pinnedCerts.length > 0) {
      agentOptions.checkServerIdentity = this.createPinningValidator();
    }

    return new https.Agent(agentOptions);
  }

  createPinningValidator() {
    const pinnedCerts = this.pinnedCerts;
    const logger = this.logger;
    const rotationCallback = this.certRotationCallback;

    return (hostname, cert) => {
      // Standard hostname verification first
      const hostErr = tls.checkServerIdentity(hostname, cert);
      if (hostErr) {
        logger.error(`Hostname verification failed for ${hostname}`, hostErr);
        return hostErr;
      }

      // Calculate certificate fingerprint
      const fingerprint = `sha256/${crypto
        .createHash('sha256')
        .update(cert.raw)
        .digest('base64')}`;

      // Check against pinned certificates
      const isPinned = pinnedCerts.some(pin => pin.fingerprint === fingerprint);

      if (!isPinned) {
        // Check if it's a new certificate (rotation scenario)
        const certExpiry = new Date(cert.valid_to);
        const certIssuer = cert.issuer.CN;

        logger.error('Certificate pinning failed', {
          hostname,
          receivedFingerprint: fingerprint,
          expectedFingerprints: pinnedCerts.map(p => p.fingerprint),
          certExpiry: certExpiry.toISOString(),
          certIssuer
        });

        // Notify security team of potential rotation or attack
        if (rotationCallback) {
          rotationCallback({
            hostname,
            fingerprint,
            certExpiry,
            certIssuer,
            timestamp: new Date().toISOString()
          });
        }

        return new Error(
          `Certificate fingerprint mismatch for ${hostname}. ` +
          `This may indicate a MITM attack or certificate rotation.`
        );
      }

      // Log successful pinning validation
      logger.debug(`Certificate pinning validated for ${hostname}`);
      return undefined;
    };
  }

  async request(url, options = {}) {
    const agent = this.createSecureAgent();

    try {
      const response = await axios({
        url,
        httpsAgent: agent,
        timeout: options.timeout || 30000,
        validateStatus: (status) => status < 500,
        ...options
      });

      return response;
    } catch (error) {
      // Log TLS errors with context (but not sensitive data)
      if (error.code === 'UNABLE_TO_VERIFY_LEAF_SIGNATURE' ||
          error.code === 'CERT_HAS_EXPIRED' ||
          error.code === 'DEPTH_ZERO_SELF_SIGNED_CERT') {
        this.logger.error('TLS certificate error', {
          url: new URL(url).hostname,  // Don't log full URL with tokens
          errorCode: error.code,
          message: error.message
        });
      }
      throw error;
    }
  }
}

// Development-only helper for local testing
// CRITICAL: This should NEVER be used in production
function createDevOnlyLocalAgent() {
  if (process.env.NODE_ENV === 'production') {
    throw new Error(
      'SECURITY ERROR: Attempted to use development TLS agent in production!'
    );
  }

  // Only allow for explicit localhost connections
  const allowedHosts = ['localhost', '127.0.0.1', '::1'];

  console.warn(
    '⚠️  WARNING: Using development TLS agent. ' +
    'This disables certificate validation for localhost ONLY.'
  );

  return new https.Agent({
    rejectUnauthorized: true,  // Still validate!
    checkServerIdentity: (hostname, cert) => {
      // Only skip validation for localhost
      if (allowedHosts.includes(hostname)) {
        return undefined;  // Allow self-signed for localhost
      }
      // Standard validation for all other hosts
      return tls.checkServerIdentity(hostname, cert);
    }
  });
}

// Certificate rotation management
class CertificateRotationManager {
  constructor(options) {
    this.pinnedCerts = options.initialPins || [];
    this.alertService = options.alertService;
    this.configStore = options.configStore;  // Redis, Consul, etc.
  }

  async refreshPinnedCertificates() {
    // Fetch updated pins from secure configuration store
    const updatedPins = await this.configStore.get('tls:pinned-certificates');

    if (updatedPins) {
      // Validate format before accepting
      const validPins = updatedPins.filter(pin => 
        pin.fingerprint && 
        pin.fingerprint.startsWith('sha256/') &&
        pin.expiresAt &&
        new Date(pin.expiresAt) > new Date()
      );

      if (validPins.length > 0) {
        this.pinnedCerts = validPins;
        console.log(`Refreshed ${validPins.length} pinned certificates`);
      }
    }
  }

  async handleRotationAlert(details) {
    // Send alert to security team
    await this.alertService.sendAlert({
      severity: 'HIGH',
      type: 'CERTIFICATE_PIN_MISMATCH',
      details,
      action: 'Verify if this is expected certificate rotation or potential MITM'
    });
  }
}

// Usage example
const client = new SecureHttpClient({
  pinnedFingerprints: [
    { fingerprint: 'sha256/abc123...', expiresAt: '2025-06-01' },
    { fingerprint: 'sha256/def456...', expiresAt: '2025-12-01' }  // Backup pin
  ],
  logger: require('pino')(),
  onCertRotation: async (details) => {
    // Alert security team
    await sendPagerDutyAlert(details);
  }
});

module.exports = { SecureHttpClient, CertificateRotationManager };
```

**Defense in Depth Layers**:

1. **Environment separation**: Production code physically cannot use development shortcuts
```javascript
if (process.env.NODE_ENV === 'production') {
  throw new Error('SECURITY ERROR: Development agent in production!');
}
```

2. **Certificate pinning with backup pins**: Allows rotation without service disruption
```javascript
pinnedFingerprints: [
  { fingerprint: 'sha256/primary...', expiresAt: '2025-06-01' },
  { fingerprint: 'sha256/backup...', expiresAt: '2025-12-01' }
]
```

3. **Automated rotation alerting**: Detect unexpected certificate changes
```javascript
onCertRotation: async (details) => {
  await sendPagerDutyAlert(details);
}
```

**Additional Protections**:
- **TLS 1.2 minimum**: Prevents downgrade attacks to vulnerable protocols
- **Cipher suite restriction**: Only allows strong, modern ciphers
- **Hostname verification**: Ensures certificate matches requested domain
- **Certificate expiry monitoring**: Alert before certificates expire
- **Audit logging**: All TLS errors logged for security review
- **Fail-closed design**: Any validation failure blocks the connection completely

**No, this is extremely dangerous and one of the most critical security mistakes in application development.** Disabling certificate validation completely defeats the purpose of TLS/SSL and exposes your application to man-in-the-middle attacks.

**VULNERABLE CODE**:

```java
import javax.net.ssl.*;
import java.security.cert.X509Certificate;
import java.net.HttpURLConnection;
import java.net.URL;
import java.io.BufferedReader;
import java.io.InputStreamReader;

public class InsecureApiClient {

    // DANGEROUS: Disables ALL certificate validation
    public static void disableCertificateValidation() {
        TrustManager[] trustAllCerts = new TrustManager[] {
            new X509TrustManager() {
                public X509Certificate[] getAcceptedIssuers() {
                    return null;  // Accept any issuer
                }
                public void checkClientTrusted(X509Certificate[] certs, String authType) {
                    // Do nothing - trust everything
                }
                public void checkServerTrusted(X509Certificate[] certs, String authType) {
                    // Do nothing - trust everything (CRITICAL FLAW)
                }
            }
        };

        try {
            SSLContext sc = SSLContext.getInstance("TLS");
            sc.init(null, trustAllCerts, new java.security.SecureRandom());
            HttpsURLConnection.setDefaultSSLSocketFactory(sc.getSocketFactory());

            // Also disable hostname verification
            HttpsURLConnection.setDefaultHostnameVerifier((hostname, session) -> true);
        } catch (Exception e) {
            e.printStackTrace();
        }
    }

    public String callApi(String apiUrl) throws Exception {
        disableCertificateValidation();  // Called before every request!

        URL url = new URL(apiUrl);
        HttpURLConnection conn = (HttpURLConnection) url.openConnection();
        BufferedReader reader = new BufferedReader(
            new InputStreamReader(conn.getInputStream()));

        StringBuilder response = new StringBuilder();
        String line;
        while ((line = reader.readLine()) != null) {
            response.append(line);
        }
        reader.close();
        return response.toString();
    }
}
```

**Attack Scenario** (MITM with tools like mitmproxy):
```bash
# Attacker on same network intercepts traffic
mitmproxy --mode transparent --ssl-insecure

# Traffic flow:
# Client -> Attacker (presents fake cert) -> Real Server
# Client accepts fake cert because validation is disabled
# Attacker sees ALL data including credentials, tokens, PII
```

**Why This Is Dangerous**:
- **Complete MITM vulnerability**: Any attacker on the network path can intercept ALL traffic
- **Credential theft**: Authentication tokens, passwords, API keys are exposed in plaintext to attackers
- **Data tampering**: Attackers can modify responses, inject malicious content
- **False sense of security**: The "https://" URL gives developers false confidence
- **Compliance violations**: Violates PCI-DSS 4.1, HIPAA, SOC2 requirements for encrypted data in transit

**SECURE VERSION**:

```java
import javax.net.ssl.*;
import java.io.FileInputStream;
import java.io.BufferedReader;
import java.io.InputStreamReader;
import java.net.HttpURLConnection;
import java.net.URL;
import java.security.KeyStore;
import java.security.cert.CertificateFactory;
import java.security.cert.X509Certificate;
import java.util.logging.Logger;

public class SecureApiClient {
    private static final Logger logger = Logger.getLogger(SecureApiClient.class.getName());
    private final SSLContext sslContext;
    private final HostnameVerifier hostnameVerifier;

    public SecureApiClient(String truststorePath, String truststorePassword) 
            throws Exception {
        // Load custom truststore with internal CA certificates
        KeyStore trustStore = KeyStore.getInstance("JKS");
        try (FileInputStream fis = new FileInputStream(truststorePath)) {
            trustStore.load(fis, truststorePassword.toCharArray());
        }

        // Initialize TrustManagerFactory with our truststore
        TrustManagerFactory tmf = TrustManagerFactory.getInstance(
            TrustManagerFactory.getDefaultAlgorithm());
        tmf.init(trustStore);

        // Create SSL context with proper certificate validation
        this.sslContext = SSLContext.getInstance("TLSv1.3");
        this.sslContext.init(null, tmf.getTrustManagers(), new java.security.SecureRandom());

        // Use default hostname verifier (validates hostname matches certificate)
        this.hostnameVerifier = HttpsURLConnection.getDefaultHostnameVerifier();

        logger.info("SecureApiClient initialized with custom truststore");
    }

    public String callApi(String apiUrl) throws Exception {
        URL url = new URL(apiUrl);

        if (!"https".equalsIgnoreCase(url.getProtocol())) {
            throw new SecurityException("Only HTTPS connections are allowed");
        }

        HttpsURLConnection conn = (HttpsURLConnection) url.openConnection();
        conn.setSSLSocketFactory(sslContext.getSocketFactory());
        conn.setHostnameVerifier(hostnameVerifier);
        conn.setConnectTimeout(10000);
        conn.setReadTimeout(30000);

        int responseCode = conn.getResponseCode();
        if (responseCode != 200) {
            logger.warning("API returned non-200 status: " + responseCode);
            throw new RuntimeException("API error: " + responseCode);
        }

        try (BufferedReader reader = new BufferedReader(
                new InputStreamReader(conn.getInputStream()))) {
            StringBuilder response = new StringBuilder();
            String line;
            while ((line = reader.readLine()) != null) {
                response.append(line);
            }
            return response.toString();
        }
    }
}
```

**Key Security Controls**:
- **Custom truststore**: Add your internal CA to a truststore instead of disabling validation entirely
- **TLS 1.3 enforcement**: Uses the most secure TLS version available
- **Hostname verification**: Ensures the certificate matches the server you're connecting to
- **Protocol enforcement**: Rejects non-HTTPS connections at the application layer
- **Proper timeout handling**: Prevents resource exhaustion attacks

**Excellent question - this is a common production challenge.** The solution is environment-aware certificate management with certificate pinning for production and controlled validation for development.

**PRODUCTION PATTERN**:

```java
import javax.net.ssl.*;
import java.io.FileInputStream;
import java.io.InputStream;
import java.net.URL;
import java.security.KeyStore;
import java.security.MessageDigest;
import java.security.cert.Certificate;
import java.security.cert.CertificateException;
import java.security.cert.X509Certificate;
import java.util.*;
import java.util.concurrent.ConcurrentHashMap;
import java.util.logging.Logger;
import java.util.Base64;

public class ProductionApiClient {
    private static final Logger logger = Logger.getLogger(ProductionApiClient.class.getName());

    // Environment detection
    private final Environment environment;
    private final Map<String, SSLContext> sslContextCache = new ConcurrentHashMap<>();
    private final Map<String, Set<String>> pinnedCertificates = new ConcurrentHashMap<>();

    public enum Environment {
        DEVELOPMENT, STAGING, PRODUCTION
    }

    public ProductionApiClient() {
        String env = System.getenv("APP_ENVIRONMENT");
        this.environment = env != null ? 
            Environment.valueOf(env.toUpperCase()) : Environment.PRODUCTION;

        // Load pinned certificates for production
        if (environment == Environment.PRODUCTION) {
            loadPinnedCertificates();
        }

        logger.info("ApiClient initialized for environment: " + environment);
    }

    private void loadPinnedCertificates() {
        // Pin SHA-256 fingerprints of known good certificates
        // These should be loaded from secure configuration
        pinnedCertificates.put("api.internal.company.com", new HashSet<>(Arrays.asList(
            "sha256/AAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAA=",  // Primary cert
            "sha256/BBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBB="   // Backup cert
        )));
        pinnedCertificates.put("auth.internal.company.com", new HashSet<>(Arrays.asList(
            "sha256/CCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCC="
        )));
    }

    public SSLContext getSSLContext(String hostname) throws Exception {
        return sslContextCache.computeIfAbsent(hostname, h -> {
            try {
                return createSSLContext(h);
            } catch (Exception e) {
                throw new RuntimeException("Failed to create SSL context for " + h, e);
            }
        });
    }

    private SSLContext createSSLContext(String hostname) throws Exception {
        KeyStore trustStore = loadTrustStore();

        TrustManagerFactory tmf = TrustManagerFactory.getInstance(
            TrustManagerFactory.getDefaultAlgorithm());
        tmf.init(trustStore);

        TrustManager[] trustManagers;

        if (environment == Environment.PRODUCTION) {
            // Wrap with certificate pinning in production
            trustManagers = new TrustManager[] {
                new PinningTrustManager(
                    (X509TrustManager) tmf.getTrustManagers()[0],
                    hostname,
                    pinnedCertificates.get(hostname)
                )
            };
        } else if (environment == Environment.STAGING) {
            // Standard validation for staging
            trustManagers = tmf.getTrustManagers();
        } else {
            // Development: allow self-signed but log warnings
            trustManagers = new TrustManager[] {
                new DevelopmentTrustManager(
                    (X509TrustManager) tmf.getTrustManagers()[0]
                )
            };
        }

        SSLContext sslContext = SSLContext.getInstance("TLSv1.3");
        sslContext.init(null, trustManagers, new java.security.SecureRandom());
        return sslContext;
    }

    private KeyStore loadTrustStore() throws Exception {
        KeyStore trustStore = KeyStore.getInstance("JKS");

        String trustStorePath = System.getenv("TRUSTSTORE_PATH");
        String trustStorePass = System.getenv("TRUSTSTORE_PASSWORD");

        if (trustStorePath != null && trustStorePass != null) {
            // Load custom truststore
            try (FileInputStream fis = new FileInputStream(trustStorePath)) {
                trustStore.load(fis, trustStorePass.toCharArray());
            }
            logger.info("Loaded custom truststore from: " + trustStorePath);
        } else {
            // Fall back to default JVM truststore
            trustStore.load(null, null);

            // Add system CA certificates
            TrustManagerFactory defaultTmf = TrustManagerFactory.getInstance(
                TrustManagerFactory.getDefaultAlgorithm());
            defaultTmf.init((KeyStore) null);

            logger.info("Using default JVM truststore");
        }

        return trustStore;
    }

    // Certificate pinning trust manager for production
    private static class PinningTrustManager implements X509TrustManager {
        private final X509TrustManager delegate;
        private final String hostname;
        private final Set<String> pinnedFingerprints;

        public PinningTrustManager(X509TrustManager delegate, 
                                   String hostname, 
                                   Set<String> pinnedFingerprints) {
            this.delegate = delegate;
            this.hostname = hostname;
            this.pinnedFingerprints = pinnedFingerprints != null ? 
                pinnedFingerprints : Collections.emptySet();
        }

        @Override
        public void checkServerTrusted(X509Certificate[] chain, String authType) 
                throws CertificateException {
            // First, perform standard certificate validation
            delegate.checkServerTrusted(chain, authType);

            // Then verify certificate pinning
            if (!pinnedFingerprints.isEmpty()) {
                boolean pinMatched = false;
                for (X509Certificate cert : chain) {
                    String fingerprint = getFingerprint(cert);
                    if (pinnedFingerprints.contains(fingerprint)) {
                        pinMatched = true;
                        break;
                    }
                }

                if (!pinMatched) {
                    logger.severe("Certificate pin validation failed for: " + hostname);
                    throw new CertificateException(
                        "Certificate pinning failed - possible MITM attack");
                }

                logger.fine("Certificate pin validated for: " + hostname);
            }
        }

        private String getFingerprint(X509Certificate cert) throws CertificateException {
            try {
                MessageDigest md = MessageDigest.getInstance("SHA-256");
                byte[] digest = md.digest(cert.getPublicKey().getEncoded());
                return "sha256/" + Base64.getEncoder().encodeToString(digest);
            } catch (Exception e) {
                throw new CertificateException("Failed to compute certificate fingerprint", e);
            }
        }

        @Override
        public void checkClientTrusted(X509Certificate[] chain, String authType) 
                throws CertificateException {
            delegate.checkClientTrusted(chain, authType);
        }

        @Override
        public X509Certificate[] getAcceptedIssuers() {
            return delegate.getAcceptedIssuers();
        }
    }

    // Development trust manager - validates but allows self-signed with warnings
    private static class DevelopmentTrustManager implements X509TrustManager {
        private final X509TrustManager delegate;

        public DevelopmentTrustManager(X509TrustManager delegate) {
            this.delegate = delegate;
        }

        @Override
        public void checkServerTrusted(X509Certificate[] chain, String authType) 
                throws CertificateException {
            try {
                delegate.checkServerTrusted(chain, authType);
            } catch (CertificateException e) {
                // In development, log warning but allow self-signed
                logger.warning("DEV MODE: Allowing untrusted certificate: " + 
                    chain[0].getSubjectX500Principal().getName() + 
                    " - Reason: " + e.getMessage());

                // Still validate basic certificate structure
                for (X509Certificate cert : chain) {
                    cert.checkValidity();  // Check not expired
                }
            }
        }

        @Override
        public void checkClientTrusted(X509Certificate[] chain, String authType) 
                throws CertificateException {
            delegate.checkClientTrusted(chain, authType);
        }

        @Override
        public X509Certificate[] getAcceptedIssuers() {
            return delegate.getAcceptedIssuers();
        }
    }

    // Secure hostname verifier with logging
    public HostnameVerifier getHostnameVerifier() {
        return (hostname, session) -> {
            HostnameVerifier defaultVerifier = HttpsURLConnection.getDefaultHostnameVerifier();
            boolean valid = defaultVerifier.verify(hostname, session);

            if (!valid) {
                logger.severe("Hostname verification failed: " + hostname + 
                    " does not match certificate");
            }

            return valid;
        };
    }
}
```

**Defense in Depth Layers**:

1. **Environment-aware validation**:
```java
// Production: Full validation + certificate pinning
// Staging: Full validation, no pinning
// Development: Validation with warnings for self-signed

if (environment == Environment.PRODUCTION) {
    // Maximum security
    trustManagers = new TrustManager[] {
        new PinningTrustManager(baseTrustManager, hostname, pins)
    };
}
```

2. **Certificate pinning**:
```java
// Pin public key fingerprints, not full certificates
// This survives certificate rotation
private String getFingerprint(X509Certificate cert) {
    MessageDigest md = MessageDigest.getInstance("SHA-256");
    byte[] digest = md.digest(cert.getPublicKey().getEncoded());
    return "sha256/" + Base64.getEncoder().encodeToString(digest);
}
