// CertificatePinner provides certificate pinning functionality
type CertificatePinner struct {
	pinnedHashes map[string][]string // hostname -> list of valid SPKI hashes
	mu           sync.RWMutex
}

// NewCertificatePinner creates a pinner with predefined pins
func NewCertificatePinner() *CertificatePinner {
	return &CertificatePinner{
		pinnedHashes: map[string][]string{
			// Pin both current and backup certificates
			"api.payment-processor.com": {
				"sha256/AAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAA=", // Current cert
				"sha256/BBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBB=", // Backup cert
			},
			"api.internal-service.local": {
				"sha256/CCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCC=",
			},
		},
	}
}

// VerifyPeerCertificate implements certificate pinning
func (cp *CertificatePinner) VerifyPeerCertificate(rawCerts [][]byte, verifiedChains [][]*x509.Certificate) error {
	if len(verifiedChains) == 0 || len(verifiedChains[0]) == 0 {
		return fmt.Errorf("no verified certificate chains")
	}

	leafCert := verifiedChains[0][0]
	hostname := leafCert.Subject.CommonName

	cp.mu.RLock()
	pinnedHashes, exists := cp.pinnedHashes[hostname]
	cp.mu.RUnlock()

	// If no pins defined for this host, allow (fall back to CA validation)
	if !exists {
		log.Printf("[WARN] No certificate pins for host: %s", hostname)
		return nil
	}

	// Calculate SPKI hash of the leaf certificate
	spkiHash := calculateSPKIHash(leafCert)

	// Check if the certificate matches any pinned hash
	for _, pinnedHash := range pinnedHashes {
		if spkiHash == pinnedHash {
			log.Printf("[INFO] Certificate pin verified for: %s", hostname)
			return nil
		}
	}

	log.Printf("[CRITICAL] Certificate pin mismatch for %s! Expected: %v, Got: %s",
		hostname, pinnedHashes, spkiHash)
	return fmt.Errorf("certificate pin verification failed for %s", hostname)
}

func calculateSPKIHash(cert *x509.Certificate) string {
	hash := sha256.Sum256(cert.RawSubjectPublicKeyInfo)
	return "sha256/" + base64.StdEncoding.EncodeToString(hash[:])
}

// SecureHTTPClient creates a production-ready HTTP client
type SecureHTTPClient struct {
	client   *http.Client
	pinner   *CertificatePinner
	logger   *log.Logger
	env      string
}

// NewSecureHTTPClient creates a new secure client based on environment
func NewSecureHTTPClient(env string) (*SecureHTTPClient, error) {
	logger := log.New(os.Stdout, "[SecureHTTP] ", log.LstdFlags|log.Lshortfile)

	rootCAs, err := x509.SystemCertPool()
	if err != nil {
		return nil, fmt.Errorf("failed to load system CA pool: %w", err)
	}

	pinner := NewCertificatePinner()

	var tlsConfig *tls.Config

	switch env {
	case "production":
		tlsConfig = &tls.Config{
			RootCAs:                  rootCAs,
			MinVersion:               tls.VersionTLS13, // TLS 1.3 only in production
			InsecureSkipVerify:       false,
			VerifyPeerCertificate:    pinner.VerifyPeerCertificate,
			SessionTicketsDisabled:   false,
			PreferServerCipherSuites: true,
		}
		logger.Println("Initialized with PRODUCTION TLS config (TLS 1.3 + pinning)")

	case "staging":
		tlsConfig = &tls.Config{
			RootCAs:               rootCAs,
			MinVersion:            tls.VersionTLS12,
			InsecureSkipVerify:    false,
			VerifyPeerCertificate: pinner.VerifyPeerCertificate,
		}
		logger.Println("Initialized with STAGING TLS config (TLS 1.2+ with pinning)")

	case "development":
		// Development: Add custom CA for internal self-signed certs
		if devCAPath := os.Getenv("DEV_CA_CERT_PATH"); devCAPath != "" {
			devCACert, err := os.ReadFile(devCAPath)
			if err != nil {
				return nil, fmt.Errorf("failed to read dev CA cert: %w", err)
			}
			if !rootCAs.AppendCertsFromPEM(devCACert) {
				return nil, fmt.Errorf("failed to append dev CA certificate")
			}
			logger.Printf("Added development CA from: %s", devCAPath)
		}
		tlsConfig = &tls.Config{
			RootCAs:            rootCAs,
			MinVersion:         tls.VersionTLS12,
			InsecureSkipVerify: false, // STILL validate against the custom CA!
		}
		logger.Println("Initialized with DEVELOPMENT TLS config (custom CA support)")

	default:
		return nil, fmt.Errorf("unknown environment: %s", env)
	}

	transport := &http.Transport{
		TLSClientConfig:       tlsConfig,
		MaxIdleConns:          100,
		MaxIdleConnsPerHost:   10,
		IdleConnTimeout:       90 * time.Second,
		TLSHandshakeTimeout:   10 * time.Second,
		ExpectContinueTimeout: 1 * time.Second,
		ForceAttemptHTTP2:     true,
	}

	return &SecureHTTPClient{
		client: &http.Client{
			Transport: transport,
			Timeout:   30 * time.Second,
		},
		pinner: pinner,
		logger: logger,
		env:    env,
	}, nil
}

// DoRequest performs a secure HTTP request with logging and monitoring
func (s *SecureHTTPClient) DoRequest(ctx context.Context, method, url string, body io.Reader) (*http.Response, error) {
	req, err := http.NewRequestWithContext(ctx, method, url, body)
	if err != nil {
		return nil, fmt.Errorf("failed to create request: %w", err)
	}

	start := time.Now()

	resp, err := s.client.Do(req)

	duration := time.Since(start)

	if err != nil {
		s.logger.Printf("[ERROR] %s %s failed after %v: %v", method, url, duration, err)
		// Check for certificate errors specifically
		if isCertificateError(err) {
			s.logger.Printf("[SECURITY] Certificate validation failure for %s - possible MITM attack!", url)
			// Alert security team in production
			if s.env == "production" {
				alertSecurityTeam(url, err)
			}
		}
		return nil, err
	}

	s.logger.Printf("[INFO] %s %s completed in %v with status %d", method, url, duration, resp.StatusCode)

	return resp, nil
}

func isCertificateError(err error) bool {
	errStr := err.Error()
	return contains(errStr, "certificate") ||
		contains(errStr, "x509") ||
		contains(errStr, "tls") ||
		contains(errStr, "pin")
}

func contains(s, substr string) bool {
	return len(s) >= len(substr) && (s == substr || len(s) > 0 && containsRune(s, substr))
}

func containsRune(s, substr string) bool {
	for i := 0; i <= len(s)-len(substr); i++ {
		if s[i:i+len(substr)] == substr {
			return true
		}
	}
	return false
}

func alertSecurityTeam(url string, err error) {
	// In production: Send to SIEM, PagerDuty, Slack, etc.
	log.Printf("[ALERT] Security team notified of certificate issue: %s - %v", url, err)
}

func main() {
