```csharp
using System;
using System.Net.Http;
using System.Security.Cryptography;
using System.Security.Cryptography.X509Certificates;
using Microsoft.Extensions.Logging;
using Microsoft.Extensions.Options;

namespace SecureApp.Services
{
    public class CertificateConfig
    {
        public string[] TrustedThumbprints { get; set; } = Array.Empty<string>();
        public string[] TrustedSubjectNames { get; set; } = Array.Empty<string>();
        public string PrivateCACertificatePath { get; set; } = string.Empty;
        public bool EnforcePinning { get; set; } = true;
    }

    public class SecureCertificateValidator
    {
        private readonly CertificateConfig _config;
        private readonly ILogger<SecureCertificateValidator> _logger;
        private readonly X509Certificate2? _privateCACert;

        public SecureCertificateValidator(
            IOptions<CertificateConfig> config,
            ILogger<SecureCertificateValidator> logger)
        {
            _config = config.Value;
            _logger = logger;

            // Load private CA certificate if configured
            if (!string.IsNullOrEmpty(_config.PrivateCACertificatePath))
            {
                _privateCACert = new X509Certificate2(_config.PrivateCACertificatePath);
                _logger.LogInformation("Loaded private CA certificate: {Subject}", 
                    _privateCACert.Subject);
            }
        }

        public bool ValidateCertificate(
            HttpRequestMessage request,
            X509Certificate2? certificate,
            X509Chain? chain,
            SslPolicyErrors sslPolicyErrors)
        {
            if (certificate == null)
            {
                _logger.LogWarning("Certificate validation failed: No certificate provided");
                return false;
            }

            var thumbprint = certificate.Thumbprint;
            var subject = certificate.Subject;
            var host = request.RequestUri?.Host ?? "unknown";

            // LAYER 1: Check for critical errors (revoked, etc.)
            if (sslPolicyErrors.HasFlag(SslPolicyErrors.RemoteCertificateNotAvailable))
            {
                _logger.LogError("Certificate not available for host {Host}", host);
                return false;
            }

            // LAYER 2: Certificate pinning - check against known thumbprints
            if (_config.TrustedThumbprints.Length > 0)
            {
                if (_config.TrustedThumbprints.Contains(thumbprint, StringComparer.OrdinalIgnoreCase))
                {
                    _logger.LogDebug("Certificate pinning succeeded for {Host} with thumbprint {Thumbprint}",
                        host, thumbprint);
                    return true;
                }

                if (_config.EnforcePinning)
                {
                    _logger.LogWarning(
                        "Certificate pinning FAILED for {Host}. Thumbprint {Thumbprint} not in trusted list",
                        host, thumbprint);
                    return false;
                }
            }

            // LAYER 3: Validate against private CA
            if (_privateCACert != null && chain != null)
            {
                chain.ChainPolicy.ExtraStore.Add(_privateCACert);
                chain.ChainPolicy.VerificationFlags = X509VerificationFlags.AllowUnknownCertificateAuthority;
                chain.ChainPolicy.RevocationMode = X509RevocationMode.NoCheck; // Configure based on your PKI

                bool isValidChain = chain.Build(certificate);

                // Verify the chain ends with our private CA
                if (isValidChain)
                {
                    var rootCert = chain.ChainElements[^1].Certificate;
                    if (rootCert.Thumbprint.Equals(_privateCACert.Thumbprint, StringComparison.OrdinalIgnoreCase))
                    {
                        _logger.LogDebug("Private CA validation succeeded for {Host}", host);
                        return true;
                    }
                }

                _logger.LogWarning("Private CA validation failed for {Host}", host);
            }

            // LAYER 4: If no pinning/private CA, require valid public chain
            if (sslPolicyErrors == SslPolicyErrors.None)
            {
                _logger.LogDebug("Standard certificate validation succeeded for {Host}", host);
                return true;
            }

            // Log detailed failure information for debugging
            _logger.LogError(
                "Certificate validation FAILED for {Host}. Subject: {Subject}, Errors: {Errors}",
                host, subject, sslPolicyErrors);

            return false;
        }
    }

    public class SecureInternalApiClient : IDisposable
    {
        private readonly HttpClient _httpClient;
        private readonly ILogger<SecureInternalApiClient> _logger;
        private readonly SecureCertificateValidator _validator;

        public SecureInternalApiClient(
            SecureCertificateValidator validator,
            ILogger<SecureInternalApiClient> logger)
        {
            _validator = validator;
            _logger = logger;

            var handler = new HttpClientHandler
            {
                ServerCertificateCustomValidationCallback = _validator.ValidateCertificate,
                SslProtocols = System.Security.Authentication.SslProtocols.Tls12 | 
                               System.Security.Authentication.SslProtocols.Tls13
            };

            _httpClient = new HttpClient(handler)
            {
                Timeout = TimeSpan.FromSeconds(30)
            };
        }

        public async Task<T?> GetAsync<T>(string url) where T : class
        {
            var correlationId = Guid.NewGuid().ToString("N")[..8];

            try
            {
                _logger.LogInformation("[{CorrelationId}] Making secure request to {Url}", 
                    correlationId, url);

                var response = await _httpClient.GetAsync(url);
                response.EnsureSuccessStatusCode();

                var content = await response.Content.ReadAsStringAsync();
                return System.Text.Json.JsonSerializer.Deserialize<T>(content);
            }
            catch (HttpRequestException ex) when (
                ex.InnerException is System.Security.Authentication.AuthenticationException)
            {
                _logger.LogError(ex, 
                    "[{CorrelationId}] Certificate validation failed for {Url}",
                    correlationId, url);
                throw new SecurityException("Secure connection could not be established", ex);
            }
            catch (Exception ex)
            {
                _logger.LogError(ex, "[{CorrelationId}] Request failed for {Url}", 
                    correlationId, url);
                throw;
            }
        }

        public void Dispose()
        {
            _httpClient?.Dispose();
        }
    }
}
