const https = require('https');
const tls = require('tls');
const crypto = require('crypto');
const fs = require('fs');
const axios = require('axios');

class SecureHttpClient {
  constructor(options = {}) {
    this.environment = process.env.NODE_ENV || 'development';
    this.pinnedCerts = new Map();
    this.logger = options.logger || console;

    // Load pinned certificate fingerprints from secure config
    this.loadPinnedCertificates();
  }

  loadPinnedCertificates() {
    // Store SHA-256 fingerprints of expected certificates
    // These should be loaded from secure configuration
    const pins = {
      'api.payment-processor.com': [
        'sha256/AAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAA=',  // Primary
        'sha256/BBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBB='   // Backup
      ],
      'api.banking-service.com': [
        'sha256/CCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCC='
      ]
    };

    for (const [host, fingerprints] of Object.entries(pins)) {
      this.pinnedCerts.set(host, fingerprints);
    }
  }

  // Calculate certificate fingerprint
  getCertificateFingerprint(cert) {
    const der = cert.raw;
    const hash = crypto.createHash('sha256').update(der).digest('base64');
    return `sha256/${hash}`;
  }

  // Custom certificate verification with pinning
  createPinningAgent(hostname) {
    const self = this;
    const expectedPins = this.pinnedCerts.get(hostname);

    return new https.Agent({
      rejectUnauthorized: true,
      minVersion: 'TLSv1.2',

      checkServerIdentity: (host, cert) => {
        // First: standard hostname verification
        const standardError = tls.checkServerIdentity(host, cert);
        if (standardError) {
          self.logger.error(`Hostname verification failed for ${host}`);
          return standardError;
        }

        // Second: certificate pinning (if configured for this host)
        if (expectedPins && expectedPins.length > 0) {
          const certFingerprint = self.getCertificateFingerprint(cert);

          if (!expectedPins.includes(certFingerprint)) {
            const error = new Error(
              `Certificate pinning failed for ${host}. ` +
              `Expected one of: ${expectedPins.join(', ')}, ` +
              `Got: ${certFingerprint}`
            );
            error.code = 'CERT_PIN_MISMATCH';

            // Alert security team on pinning failure
            self.logSecurityEvent('CERT_PIN_FAILURE', {
              hostname: host,
              expectedPins,
              actualPin: certFingerprint,
              certSubject: cert.subject,
              certIssuer: cert.issuer
            });

            return error;
          }

          self.logger.debug(`Certificate pinning verified for ${host}`);
        }

        return undefined;  // Success
      }
    });
  }

  // Create agent for development with proper local certificates
  createDevelopmentAgent() {
    // For development: use local CA, but STILL validate!
    const devCaCertPath = process.env.DEV_CA_CERT_PATH || './certs/dev-ca.pem';

    if (!fs.existsSync(devCaCertPath)) {
      throw new Error(
        'Development CA certificate not found. ' +
        'Generate one with: npm run generate-dev-certs'
      );
    }

    return new https.Agent({
      ca: fs.readFileSync(devCaCertPath),
      rejectUnauthorized: true,  // STILL VALIDATE in development!
      minVersion: 'TLSv1.2'
    });
  }

  async request(url, options = {}) {
    const urlObj = new URL(url);
    const hostname = urlObj.hostname;

    let httpsAgent;

    if (this.environment === 'development' && hostname === 'localhost') {
      // Development with local services
      httpsAgent = this.createDevelopmentAgent();
    } else if (this.pinnedCerts.has(hostname)) {
      // Critical API with certificate pinning
      httpsAgent = this.createPinningAgent(hostname);
    } else {
      // Standard HTTPS with system CA store
      httpsAgent = new https.Agent({
        rejectUnauthorized: true,
        minVersion: 'TLSv1.2'
      });
    }

    try {
      const response = await axios({
        url,
        httpsAgent,
        timeout: options.timeout || 30000,
        ...options
      });

      return response;
    } catch (error) {
      if (error.code === 'CERT_PIN_MISMATCH') {
        // Don't retry on pinning failures - this is an attack
        throw error;
      }

      if (error.code === 'UNABLE_TO_VERIFY_LEAF_SIGNATURE') {
        this.logger.error(
          `SSL verification failed for ${hostname}. ` +
          'Do NOT disable verification - fix the certificate issue.'
        );
      }

      throw error;
    }
  }

  logSecurityEvent(eventType, details) {
    const event = {
      timestamp: new Date().toISOString(),
      type: eventType,
      severity: 'CRITICAL',
      ...details
    };

    // Log to security monitoring system
    this.logger.error('[SECURITY]', JSON.stringify(event));

    // In production, also send to SIEM/alerting
    if (this.environment === 'production') {
      // sendToSecurityMonitoring(event);
    }
  }
}

