**PRODUCTION PATTERN**:

```java
import javax.net.ssl.*;
import java.io.*;
import java.net.URL;
import java.security.*;
import java.security.cert.*;
import java.util.*;
import java.util.logging.Logger;
import java.util.Base64;

public class ProductionSecureHttpClient {
    private static final Logger logger = Logger.getLogger(ProductionSecureHttpClient.class.getName());

    // Pin to specific certificate public key hashes (SHA-256)
    private static final Set<String> PINNED_CERTIFICATES = Set.of(
        "sha256/AAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAA=",  // Primary cert
        "sha256/BBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBB="   // Backup cert
    );

    private final SSLSocketFactory sslSocketFactory;
    private final boolean enablePinning;
    private final String environment;

    public ProductionSecureHttpClient(String environment) throws Exception {
        this.environment = environment;
        this.enablePinning = "production".equals(environment);

        SSLContext sslContext;

        if ("test".equals(environment) || "development".equals(environment)) {
            // For non-production: trust specific self-signed cert
            sslContext = createTestSslContext();
            logger.warning("Using test SSL context - NOT FOR PRODUCTION");
        } else {
            // Production: use system truststore with certificate pinning
            sslContext = createProductionSslContext();
            logger.info("Using production SSL context with certificate pinning");
        }

        this.sslSocketFactory = sslContext.getSocketFactory();
    }

    private SSLContext createTestSslContext() throws Exception {
        // Load ONLY the specific test certificate - NOT a trust-all manager
        String testCertPath = System.getenv("TEST_CERT_PATH");
        if (testCertPath == null || testCertPath.isEmpty()) {
            throw new SecurityException("TEST_CERT_PATH environment variable required");
        }

        CertificateFactory cf = CertificateFactory.getInstance("X.509");
        X509Certificate testCert;
        try (FileInputStream fis = new FileInputStream(testCertPath)) {
            testCert = (X509Certificate) cf.generateCertificate(fis);
        }

        // Validate certificate is not expired
        testCert.checkValidity();

        // Create keystore with only this certificate
        KeyStore ks = KeyStore.getInstance(KeyStore.getDefaultType());
        ks.load(null, null);
        ks.setCertificateEntry("test-server", testCert);

        TrustManagerFactory tmf = TrustManagerFactory.getInstance(
            TrustManagerFactory.getDefaultAlgorithm());
        tmf.init(ks);

        SSLContext sslContext = SSLContext.getInstance("TLSv1.3");
        sslContext.init(null, tmf.getTrustManagers(), new SecureRandom());

        return sslContext;
    }

    private SSLContext createProductionSslContext() throws Exception {
        // Use system truststore with pinning verification
        TrustManagerFactory tmf = TrustManagerFactory.getInstance(
            TrustManagerFactory.getDefaultAlgorithm());
        tmf.init((KeyStore) null);  // Use system default truststore

        // Wrap trust managers with pinning check
        TrustManager[] trustManagers = tmf.getTrustManagers();
        TrustManager[] pinnedManagers = new TrustManager[trustManagers.length];

        for (int i = 0; i < trustManagers.length; i++) {
            if (trustManagers[i] instanceof X509TrustManager) {
                pinnedManagers[i] = new PinningTrustManager(
                    (X509TrustManager) trustManagers[i]);
            } else {
                pinnedManagers[i] = trustManagers[i];
            }
        }

        SSLContext sslContext = SSLContext.getInstance("TLSv1.3");
        sslContext.init(null, pinnedManagers, new SecureRandom());

        return sslContext;
    }

    // Custom TrustManager that adds certificate pinning
    private class PinningTrustManager implements X509TrustManager {
        private final X509TrustManager delegate;

        PinningTrustManager(X509TrustManager delegate) {
            this.delegate = delegate;
        }

        @Override
        public void checkServerTrusted(X509Certificate[] chain, String authType)
                throws CertificateException {
            // First: standard certificate validation
            delegate.checkServerTrusted(chain, authType);

            // Second: certificate pinning validation
            if (enablePinning && !validatePins(chain)) {
                logger.severe("Certificate pinning validation FAILED!");
                throw new CertificateException(
                    "Certificate does not match pinned public key");
            }

            logger.fine("Certificate validation and pinning check passed");
        }

        @Override
        public void checkClientTrusted(X509Certificate[] chain, String authType)
                throws CertificateException {
            delegate.checkClientTrusted(chain, authType);
        }

        @Override
        public X509Certificate[] getAcceptedIssuers() {
            return delegate.getAcceptedIssuers();
        }

        private boolean validatePins(X509Certificate[] chain) {
            for (X509Certificate cert : chain) {
                String certPin = calculatePin(cert);
                if (PINNED_CERTIFICATES.contains(certPin)) {
                    logger.fine("Matched pinned certificate: " + certPin);
                    return true;
                }
            }
            return false;
        }

        private String calculatePin(X509Certificate cert) {
            try {
                MessageDigest md = MessageDigest.getInstance("SHA-256");
                byte[] publicKeyBytes = cert.getPublicKey().getEncoded();
                byte[] hash = md.digest(publicKeyBytes);
                return "sha256/" + Base64.getEncoder().encodeToString(hash);
            } catch (NoSuchAlgorithmException e) {
                throw new RuntimeException("SHA-256 not available", e);
            }
        }
    }

    public String secureRequest(String urlString) throws Exception {
        URL url = new URL(urlString);
        HttpsURLConnection conn = (HttpsURLConnection) url.openConnection();

        conn.setSSLSocketFactory(sslSocketFactory);
        conn.setConnectTimeout(10000);
        conn.setReadTimeout(30000);

        // Strict hostname verification
        conn.setHostnameVerifier((hostname, session) -> {
            HostnameVerifier hv = HttpsURLConnection.getDefaultHostnameVerifier();
            boolean valid = hv.verify(hostname, session);
            if (!valid) {
                logger.severe("Hostname verification failed for: " + hostname);
            }
            return valid;
        });

        // Log certificate chain for monitoring
        logCertificateChain(conn);

        int responseCode = conn.getResponseCode();
        if (responseCode != 200) {
            throw new IOException("HTTP error: " + responseCode);
        }

        try (BufferedReader reader = new BufferedReader(
                new InputStreamReader(conn.getInputStream()))) {
            StringBuilder response = new StringBuilder();
            String line;
            while ((line = reader.readLine()) != null) {
                response.append(line);
            }
            return response.toString();
        }
    }

    private void logCertificateChain(HttpsURLConnection conn) {
        try {
            Certificate[] certs = conn.getServerCertificates();
            for (int i = 0; i < certs.length; i++) {
                if (certs[i] instanceof X509Certificate) {
                    X509Certificate x509 = (X509Certificate) certs[i];
                    logger.info(String.format(
                        "Cert[%d]: Subject=%s, Issuer=%s, Expires=%s",
                        i,
                        x509.getSubjectX500Principal().getName(),
                        x509.getIssuerX500Principal().getName(),
                        x509.getNotAfter()
                    ));
                }
            }
        } catch (SSLPeerUnverifiedException e) {
            logger.severe("Could not verify peer certificate: " + e.getMessage());
        }
    }
}
