This is a common requirement, but it must be handled carefully to prevent development shortcuts from reaching production. The key is certificate pinning for internal services and strict environment controls.

**PRODUCTION PATTERN**:

```go
package main

import (
	"crypto/sha256"
	"crypto/tls"
	"crypto/x509"
	"encoding/hex"
	"fmt"
	"io"
	"log"
	"net/http"
	"os"
	"strings"
	"time"
)

type SecureHTTPClient struct {
	client      *http.Client
	pinnedCerts map[string][]string // hostname -> list of pinned cert fingerprints
	logger      *log.Logger
	env         string
}

func NewSecureHTTPClient() (*SecureHTTPClient, error) {
	env := os.Getenv("APP_ENV")
	if env == "" {
		env = "production" // Default to most secure
	}

	logger := log.New(os.Stdout, "[HTTPS-CLIENT] ", log.LstdFlags|log.Lshortfile)

	// Load CA certificates
	rootCAs, err := x509.SystemCertPool()
	if err != nil {
		rootCAs = x509.NewCertPool()
		logger.Printf("WARNING: Could not load system CA pool: %v", err)
	}

	// Add internal CA if configured
	if internalCAPath := os.Getenv("INTERNAL_CA_CERT"); internalCAPath != "" {
		caCert, err := os.ReadFile(internalCAPath)
		if err != nil {
			return nil, fmt.Errorf("failed to read internal CA: %w", err)
		}
		if !rootCAs.AppendCertsFromPEM(caCert) {
			return nil, fmt.Errorf("failed to parse internal CA certificate")
		}
		logger.Printf("Loaded internal CA from: %s", internalCAPath)
	}

	sc := &SecureHTTPClient{
		pinnedCerts: make(map[string][]string),
		logger:      logger,
		env:         env,
	}

	// Load pinned certificates from environment
	sc.loadPinnedCerts()

	minVersion := tls.VersionTLS12
	if env == "production" {
		minVersion = tls.VersionTLS13 // Stricter in production
	}

	tlsConfig := &tls.Config{
		RootCAs:            rootCAs,
		MinVersion:         uint16(minVersion),
		InsecureSkipVerify: false, // NEVER disable
		VerifyPeerCertificate: func(rawCerts [][]byte, verifiedChains [][]*x509.Certificate) error {
			return sc.verifyWithPinning(rawCerts, verifiedChains)
		},
	}

	tr := &http.Transport{
		TLSClientConfig:       tlsConfig,
		ForceAttemptHTTP2:     true,
		MaxIdleConns:          100,
		IdleConnTimeout:       90 * time.Second,
		TLSHandshakeTimeout:   10 * time.Second,
		ExpectContinueTimeout: 1 * time.Second,
		DisableCompression:    true, // Prevent CRIME attack
	}

	sc.client = &http.Client{
		Transport: tr,
		Timeout:   30 * time.Second,
	}

	return sc, nil
}

func (sc *SecureHTTPClient) loadPinnedCerts() {
	// Format: PINNED_CERTS="api.internal.com:sha256hash1,sha256hash2;db.internal.com:hash3"
	pinned := os.Getenv("PINNED_CERTS")
	if pinned == "" {
		return
	}

	for _, hostPins := range strings.Split(pinned, ";") {
		parts := strings.SplitN(hostPins, ":", 2)
		if len(parts) != 2 {
			continue
		}
		hostname := parts[0]
		hashes := strings.Split(parts[1], ",")
		sc.pinnedCerts[hostname] = hashes
		sc.logger.Printf("Loaded %d pinned certs for %s", len(hashes), hostname)
	}
}

func (sc *SecureHTTPClient) verifyWithPinning(rawCerts [][]byte, verifiedChains [][]*x509.Certificate) error {
	if len(verifiedChains) == 0 {
		return fmt.Errorf("no verified certificate chains")
	}

	leafCert := verifiedChains[0][0]
	hostname := leafCert.DNSNames[0]

	pinnedHashes, hasPins := sc.pinnedCerts[hostname]
	if !hasPins {
		// No pins configured, rely on CA validation only
		return nil
	}

	// Calculate certificate fingerprint
	certFingerprint := sha256.Sum256(leafCert.Raw)
	certHash := hex.EncodeToString(certFingerprint[:])

	// Check against pinned hashes
	for _, pinnedHash := range pinnedHashes {
		if strings.EqualFold(certHash, pinnedHash) {
			sc.logger.Printf("Certificate pin matched for %s", hostname)
			return nil
		}
	}

	sc.logger.Printf("SECURITY ALERT: Certificate pin mismatch for %s. Got: %s", hostname, certHash)
	return fmt.Errorf("certificate pin mismatch for %s", hostname)
}

func (sc *SecureHTTPClient) Get(url string) ([]byte, error) {
	sc.logger.Printf("Secure GET request to: %s (env: %s)", url, sc.env)

	resp, err := sc.client.Get(url)
	if err != nil {
		sc.logger.Printf("Request failed: %v", err)
		return nil, fmt.Errorf("secure request failed: %w", err)
	}
	defer resp.Body.Close()

	// Log TLS connection details
	if resp.TLS != nil {
		sc.logger.Printf("TLS Version: %s, Cipher: %s",
			tlsVersionString(resp.TLS.Version),
			tls.CipherSuiteName(resp.TLS.CipherSuite))
	}

	return io.ReadAll(resp.Body)
}

func tlsVersionString(version uint16) string {
	switch version {
	case tls.VersionTLS10:
		return "TLS 1.0 (INSECURE)"
	case tls.VersionTLS11:
		return "TLS 1.1 (DEPRECATED)"
	case tls.VersionTLS12:
		return "TLS 1.2"
	case tls.VersionTLS13:
		return "TLS 1.3"
	default:
		return fmt.Sprintf("Unknown (%d)", version)
	}
}

func main() {
	client, err := NewSecureHTTPClient()
	if err != nil {
		log.Fatalf("Failed to create secure client: %v", err)
	}

	data, err := client.Get("https://api.internal.company.com/config")
	if err != nil {
		log.Fatalf("Request failed: %v", err)
	}

	fmt.Printf("Received %d bytes securely\n", len(data))
}
```

