**Excellent question!** This is a common enterprise scenario. The solution is to **pin the specific certificate** or use an **internal CA**, NOT disable validation entirely. Here's how to do it securely:

**PRODUCTION PATTERN**:

```csharp
using System;
using System.Collections.Generic;
using System.Linq;
using System.Net.Http;
using System.Net.Security;
using System.Security.Cryptography;
using System.Security.Cryptography.X509Certificates;
using System.Threading.Tasks;
using Microsoft.Extensions.Configuration;
using Microsoft.Extensions.Logging;

namespace SecureApp.Infrastructure
{
    public class CertificatePinnedHttpClient : IDisposable
    {
        private readonly HttpClient _httpClient;
        private readonly ILogger<CertificatePinnedHttpClient> _logger;
        private readonly HashSet<string> _pinnedCertificateHashes;
        private readonly string _expectedHostname;

        public CertificatePinnedHttpClient(
            IConfiguration configuration,
            ILogger<CertificatePinnedHttpClient> logger)
        {
            _logger = logger;
            _expectedHostname = configuration["InternalApi:Hostname"];

            // Load pinned certificate thumbprints from secure configuration
            _pinnedCertificateHashes = configuration
                .GetSection("InternalApi:PinnedCertificates")
                .Get<string[]>()
                .ToHashSet(StringComparer.OrdinalIgnoreCase);

            var handler = new HttpClientHandler
            {
                ServerCertificateCustomValidationCallback = ValidateCertificate,
                CheckCertificateRevocationList = false // Self-signed won't have CRL
            };

            _httpClient = new HttpClient(handler)
            {
                Timeout = TimeSpan.FromSeconds(30)
            };
        }

        private bool ValidateCertificate(
            HttpRequestMessage request,
            X509Certificate2 certificate,
            X509Chain chain,
            SslPolicyErrors sslPolicyErrors)
        {
            // SECURITY CHECK 1: Verify hostname matches expected internal host
            if (!string.Equals(request.RequestUri?.Host, _expectedHostname, 
                StringComparison.OrdinalIgnoreCase))
            {
                _logger.LogWarning(
                    "Certificate validation failed: unexpected hostname {Host}", 
                    request.RequestUri?.Host);
                return false;
            }

            // SECURITY CHECK 2: Certificate must not be null
            if (certificate == null)
            {
                _logger.LogWarning("Certificate validation failed: no certificate presented");
                return false;
            }

            // SECURITY CHECK 3: Pin by SHA256 thumbprint (more secure than SHA1)
            string certHash = GetSha256Thumbprint(certificate);

            if (!_pinnedCertificateHashes.Contains(certHash))
            {
                _logger.LogError(
                    "Certificate pinning failed for {Host}. Hash: {Hash}",
                    request.RequestUri?.Host, certHash);
                return false;
            }

            // SECURITY CHECK 4: Verify certificate is not expired
            var cert2 = new X509Certificate2(certificate);
            if (DateTime.UtcNow < cert2.NotBefore || DateTime.UtcNow > cert2.NotAfter)
            {
                _logger.LogWarning(
                    "Certificate validation failed: certificate expired or not yet valid");
                return false;
            }

            _logger.LogDebug("Certificate validated successfully for {Host}", 
                request.RequestUri?.Host);
            return true;
        }

        private static string GetSha256Thumbprint(X509Certificate certificate)
        {
            using var sha256 = SHA256.Create();
            byte[] hashBytes = sha256.ComputeHash(certificate.GetRawCertData());
            return BitConverter.ToString(hashBytes).Replace("-", "");
        }

        public async Task<T> GetAsync<T>(string endpoint) where T : class
        {
            var response = await _httpClient.GetAsync(endpoint);
            response.EnsureSuccessStatusCode();
            return await System.Text.Json.JsonSerializer
                .DeserializeAsync<T>(await response.Content.ReadAsStreamAsync());
        }

        public void Dispose() => _httpClient?.Dispose();
    }

    // Alternative: Use Internal CA Trust
    public class InternalCaHttpClientFactory
    {
        private readonly X509Certificate2 _internalCaCert;
        private readonly ILogger<InternalCaHttpClientFactory> _logger;

        public InternalCaHttpClientFactory(
            IConfiguration configuration,
            ILogger<InternalCaHttpClientFactory> logger)
        {
            _logger = logger;

            // Load internal CA from secure storage (Azure Key Vault, etc.)
            string caCertPath = configuration["InternalCa:CertificatePath"];
            _internalCaCert = new X509Certificate2(caCertPath);
        }

        public HttpClient CreateClient()
        {
            var handler = new HttpClientHandler
            {
                ServerCertificateCustomValidationCallback = ValidateWithInternalCa
            };
            return new HttpClient(handler);
        }

        private bool ValidateWithInternalCa(
            HttpRequestMessage request,
            X509Certificate2 serverCert,
            X509Chain chain,
            SslPolicyErrors errors)
        {
            if (serverCert == null) return false;

            // Build chain with internal CA as trusted root
            using var customChain = new X509Chain();
            customChain.ChainPolicy.ExtraStore.Add(_internalCaCert);
            customChain.ChainPolicy.VerificationFlags = 
                X509VerificationFlags.AllowUnknownCertificateAuthority;
            customChain.ChainPolicy.RevocationMode = X509RevocationMode.NoCheck;

            bool isValid = customChain.Build(serverCert);

            // Verify chain actually roots to our internal CA
            if (isValid)
            {
                var chainRoot = customChain.ChainElements[^1].Certificate;
                isValid = chainRoot.Thumbprint == _internalCaCert.Thumbprint;
            }

            if (!isValid)
            {
                _logger.LogError(
                    "Certificate chain validation failed for {Host}. Status: {Status}",
                    request.RequestUri?.Host,
                    string.Join(", ", customChain.ChainStatus.Select(s => s.Status)));
            }

            return isValid;
        }
    }
}
